// // This module filters packets based on a 5-bit destination IP address and a 2-bit protocol type. It allows packets if the destination IP matches `11111` and the protocol type is either `11` (ICMP) or `10` (IGMP). Otherwise, the packet should be blocked.
module packet_filter (
    input [4:0] src_ip,
    input [1:0] protocol,
    output reg allow
);
    always @(*) begin
        if (src_ip == 5'b00001 && (protocol == 2'b00 || protocol == 2'b01)) 
            allow = 1'b1; // Allow the packet
        else 
            allow = 1'b0; // Block the packet
    end
endmodule
